(window.webpackJsonp=window.webpackJsonp||[]).push([[925],{900:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> waysToMakeFair = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums</span>) </span>{\\n    <span class=\\"hljs-keyword\\">let</span> sumOdd=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> sumEven=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> preSumOdd=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> preSumEven=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;nums.length;i++){\\n        <span class=\\"hljs-keyword\\">if</span>(i%<span class=\\"hljs-number\\">2</span>===<span class=\\"hljs-number\\">0</span>){\\n            sumEven+=nums[i]\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            sumOdd+=nums[i]\\n        }\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>;i&lt;nums.length;i++){\\n        <span class=\\"hljs-keyword\\">let</span> newSumOdd=<span class=\\"hljs-number\\">0</span>, newSumEven=<span class=\\"hljs-number\\">0</span>\\n\\n        <span class=\\"hljs-keyword\\">if</span>(i%<span class=\\"hljs-number\\">2</span>===<span class=\\"hljs-number\\">0</span>){\\n            newSumOdd=preSumOdd+sumEven-preSumEven-nums[i]\\n            newSumEven=preSumEven + sumOdd-preSumOdd\\n            preSumEven+=nums[i]\\n        }<span class=\\"hljs-keyword\\">else</span>{\\n            newSumOdd=preSumOdd+sumEven-preSumEven\\n            newSumEven=preSumEven + sumOdd-preSumOdd-nums[i]\\n            preSumOdd+=nums[i]\\n        }\\n        <span class=\\"hljs-comment\\">// console.log(i,newSumEven,newSumOdd)</span>\\n        <span class=\\"hljs-keyword\\">if</span>(newSumOdd===newSumEven)res++\\n    }\\n    <span class=\\"hljs-keyword\\">return</span> res\\n};\\n</code></pre>\\n"],"titleSlug":"ways-to-make-a-fair-array","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4\xa0<code>nums</code>\xa0\u3002\u4f60\u9700\u8981\u9009\u62e9 <strong>\u6070\u597d</strong>\xa0\u4e00\u4e2a\u4e0b\u6807\uff08\u4e0b\u6807\u4ece <strong>0</strong>\xa0\u5f00\u59cb\uff09\u5e76\u5220\u9664\u5bf9\u5e94\u7684\u5143\u7d20\u3002\u8bf7\u6ce8\u610f\u5269\u4e0b\u5143\u7d20\u7684\u4e0b\u6807\u53ef\u80fd\u4f1a\u56e0\u4e3a\u5220\u9664\u64cd\u4f5c\u800c\u53d1\u751f\u6539\u53d8\u3002</p>\\n\\n<p>\u6bd4\u65b9\u8bf4\uff0c\u5982\u679c\xa0<code>nums = [6,1,7,4,1]</code>\xa0\uff0c\u90a3\u4e48\uff1a</p>\\n\\n<ul>\\n\\t<li>\u9009\u62e9\u5220\u9664\u4e0b\u6807 <code>1</code> \uff0c\u5269\u4e0b\u7684\u6570\u7ec4\u4e3a\xa0<code>nums = [6,7,4,1]</code>\xa0\u3002</li>\\n\\t<li>\u9009\u62e9\u5220\u9664\u4e0b\u6807\xa0<code>2</code>\xa0\uff0c\u5269\u4e0b\u7684\u6570\u7ec4\u4e3a\xa0<code>nums = [6,1,4,1]</code>\xa0\u3002</li>\\n\\t<li>\u9009\u62e9\u5220\u9664\u4e0b\u6807\xa0<code>4</code>\xa0\uff0c\u5269\u4e0b\u7684\u6570\u7ec4\u4e3a\xa0<code>nums = [6,1,7,4]</code>\xa0\u3002</li>\\n</ul>\\n\\n<p>\u5982\u679c\u4e00\u4e2a\u6570\u7ec4\u6ee1\u8db3\u5947\u6570\u4e0b\u6807\u5143\u7d20\u7684\u548c\u4e0e\u5076\u6570\u4e0b\u6807\u5143\u7d20\u7684\u548c\u76f8\u7b49\uff0c\u8be5\u6570\u7ec4\u5c31\u662f\u4e00\u4e2a <strong>\u5e73\u8861\u6570\u7ec4</strong> \u3002</p>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de\u5220\u9664\u64cd\u4f5c\u540e\uff0c\u5269\u4e0b\u7684\u6570\u7ec4<em>\xa0</em><code>nums</code><em>\xa0</em>\u662f\xa0<strong>\u5e73\u8861\u6570\u7ec4</strong> \u7684\xa0<strong>\u65b9\u6848\u6570</strong>\xa0\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre>\\n<b>\u8f93\u5165\uff1a</b>nums = [2,1,6,4]\\n<b>\u8f93\u51fa\uff1a</b>1\\n<strong>\u89e3\u91ca\uff1a</strong>\\n\u5220\u9664\u4e0b\u6807 0 \uff1a[1,6,4] -> \u5076\u6570\u5143\u7d20\u4e0b\u6807\u4e3a\uff1a1 + 4 = 5 \u3002\u5947\u6570\u5143\u7d20\u4e0b\u6807\u4e3a\uff1a6 \u3002\u4e0d\u5e73\u8861\u3002\\n\u5220\u9664\u4e0b\u6807 1 \uff1a[2,6,4] -> \u5076\u6570\u5143\u7d20\u4e0b\u6807\u4e3a\uff1a2 + 4 = 6 \u3002\u5947\u6570\u5143\u7d20\u4e0b\u6807\u4e3a\uff1a6 \u3002\u5e73\u8861\u3002\\n\u5220\u9664\u4e0b\u6807 2 \uff1a[2,1,4] -> \u5076\u6570\u5143\u7d20\u4e0b\u6807\u4e3a\uff1a2 + 4 = 6 \u3002\u5947\u6570\u5143\u7d20\u4e0b\u6807\u4e3a\uff1a1 \u3002\u4e0d\u5e73\u8861\u3002\\n\u5220\u9664\u4e0b\u6807 3 \uff1a[2,1,6] -> \u5076\u6570\u5143\u7d20\u4e0b\u6807\u4e3a\uff1a2 + 6 = 8 \u3002\u5947\u6570\u5143\u7d20\u4e0b\u6807\u4e3a\uff1a1 \u3002\u4e0d\u5e73\u8861\u3002\\n\u53ea\u6709\u4e00\u79cd\u8ba9\u5269\u4f59\u6570\u7ec4\u6210\u4e3a\u5e73\u8861\u6570\u7ec4\u7684\u65b9\u6848\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<b>\u8f93\u5165\uff1a</b>nums = [1,1,1]\\n<b>\u8f93\u51fa\uff1a</b>3\\n<b>\u89e3\u91ca\uff1a</b>\u4f60\u53ef\u4ee5\u5220\u9664\u4efb\u610f\u5143\u7d20\uff0c\u5269\u4f59\u6570\u7ec4\u90fd\u662f\u5e73\u8861\u6570\u7ec4\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre>\\n<b>\u8f93\u5165\uff1a</b>nums = [1,2,3]\\n<b>\u8f93\u51fa\uff1a</b>0\\n<b>\u89e3\u91ca\uff1a</b>\u4e0d\u7ba1\u5220\u9664\u54ea\u4e2a\u5143\u7d20\uff0c\u5269\u4e0b\u6570\u7ec4\u90fd\u4e0d\u662f\u5e73\u8861\u6570\u7ec4\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= nums.length <= 10<sup>5</sup></code></li>\\n\\t<li><code>1 <= nums[i] <= 10<sup>4</sup></code></li>\\n</ul>\\n","title":"1664. \u751f\u6210\u5e73\u8861\u6570\u7ec4\u7684\u65b9\u6848\u6570","relatedTags":["\u8d2a\u5fc3\u7b97\u6cd5","\u52a8\u6001\u89c4\u5212"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1664"}')}}]);